+    (env.SOURCE_BUNDLES ? await env.SOURCE_BUNDLES.get(input.sourceBundleKey) : null);
+  if (!bundle) {
+    throw new Error(`Review source bundle not found: ${input.sourceBundleKey}`);
+  }
+
